+    /// Background thread that runs the generation loop
+    fn generationLoop(self: *Self) void {
+        while (self.running.load(.acquire)) {
+            var did_work = false;
+
+            // 1. Assign idle cells to pending requests
+            self.queue_mutex.lock();
+            for (self.request_queue.items) |*req| {
+                if (req.cell_id == null) {
+                    if (self.scheduler.findIdleCell()) |cell_id| {
+                        req.cell_id = cell_id;
+                        self.scheduler.submit(cell_id, req.prompt, req.max_tokens, null) catch {
+                            continue;
+                        };
+                        did_work = true;
+                        logger.info("Assigned request {} to cell {}", .{ req.id, cell_id });
+                    }
+                }
+            }
+            self.queue_mutex.unlock();
+
+            // 2. Run ONE step of scheduler (processes ALL active cells in single batch)
+            const active = self.scheduler.step() catch |err| {
+                logger.err("Scheduler step error: {}", .{err});
+                std.Thread.sleep(10_000_000); // 10ms
+                continue;
+            };
+
+            if (active) {
+                did_work = true;
+            }
+
+            // 3. Check for completed cells and dispatch responses
+            self.dispatchCompletedResponses();
+
+            // Sleep if idle to avoid busy-waiting
+            if (!did_work and self.request_queue.items.len == 0) {
+                std.Thread.sleep(10_000_000); // 10ms
+            }
+        }
+    }
+
+    /// Send responses for completed requests
+    fn dispatchCompletedResponses(self: *Self) void {
+        self.queue_mutex.lock();
+        defer self.queue_mutex.unlock();
+
+        var i: usize = 0;
+        while (i < self.request_queue.items.len) {
+            const req = &self.request_queue.items[i];
+            if (req.cell_id) |cell_id| {
+                const cell = &self.scheduler.cells[cell_id];
+                if (cell.state == CellState.completed) {
+                    // Build and send response
+                    const output = cell.getOutput();
+                    const response = self.buildChatResponse(output, cell.generated_count, req.prompt.len) catch {
+                        i += 1;
+                        continue;
+                    };
+                    defer self.allocator.free(response);
+
+                    self.sendResponse(req.stream, 200, response) catch {};
+                    req.stream.close();
+
+                    logger.info("Request {} completed: {} tokens", .{ req.id, cell.generated_count });
+
+                    // Reset cell and remove from queue
+                    cell.reset();
+                    self.allocator.free(req.prompt);
+                    _ = self.request_queue.swapRemove(i);
+                    continue; // Don't increment i
+                }
+            }
+            i += 1;
         }
     }

